  market: string;        // display name of the market
  flag: string;          // emoji flag
  region: MarketRegion;
  kind: 'region' | 'country';
  name: string;          // fund long name
  price: number;
  aum: number;           // fund net assets, 0 if unknown
  thin: boolean;         // AUM under $100M: thin-fund badge
